#include <bits/stdc++.h>
using namespace std;

static constexpr int NMAX = (int)1e5 + 5;

int p[NMAX];
int c[NMAX];
int n;

ifstream fin("servere.in");
ofstream fout("servere.out");

double det_putere(double x) {
    double min;

    min = double(p[0] - abs(x - c[0]));

    for (int i = 1; i < n; i++) {
        double putere = double(p[i] - abs(x - c[i]));

        if (putere < min)
            min = putere;
    }

    return min;
}

double cautare_ternara(double left, double right) {
    int k = 0;
    while (k < 100) {
        double m1 = left + (right - left) / 3;
        double m2 = right - (right - left) / 3;
        double f1 = det_putere(m1);
        double f2 = det_putere(m2);
        if (f1 < f2)
            left = m1;
        else
            right = m2;
        k++;
    }
    return det_putere(left);
}

int main() {
    fin >> n;

    for (int i = 0; i < n; i++) {
        fin >> p[i];
    }

    int prag_max, prag_min;

    fin >> c[0];

    prag_max = c[0];
    prag_min = c[0];

    for (int i = 1; i < n; i++) {
        fin >> c[i];

        if (c[i] > prag_max)
            prag_max = c[i];

        if (c[i] < prag_min)
            prag_min = c[i];
    }

    fout << fixed << setprecision(1)
        << cautare_ternara((double)prag_min, (double)prag_max) << endl;

    fin.close();
    fout.close();

    return 0;
}

import java.io.File;
import java.io.IOException;
import java.io.PrintWriter;
import static java.lang.Math.abs;
import java.util.Scanner;


public class Servere {
	static class Task {
		public final String inputFile = "servere.in";
		public final String outputFile = "servere.out";

		int n;
		double min;
		double max;
		double[] value1;
		double[] value2;

		public void solve() {
			readInput();
			writeOutput(getResult());
		}

		private void readInput() {
			try {
				Scanner sc = new Scanner(new File(inputFile));
				n = sc.nextInt();
				value1 = new double[n + 1];
				for (int i = 1; i <= n; i++) {
					value1[i] = sc.nextInt();
				}
				value2 = new double[n + 1];
				for (int i = 1; i <= n; i++) {
					value2[i] = sc.nextInt();
					if (i == 1) {
						max = value2[i];
						min = value2[i];
					}
					if (value2[i] > max) {
						max = value2[i];
					}
					if (value2[i] < min) {
						min = value2[i];
					}
				}
				sc.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private void writeOutput(String result) {
			try {
				PrintWriter pw = new PrintWriter(new File(outputFile));
				pw.printf("%s\n", result);
				pw.close();
			} catch (IOException e) {
				throw new RuntimeException(e);
			}
		}

		private String getResult() {
			int i;
			double elementMinim = value1[1] - abs(value2[1] - min);
			double elementMinim1, elementMinim2;
			while (max - min > 0.01) {
				elementMinim1 = value1[1] - abs(value2[1] - min);
				elementMinim2 = value1[1] - abs(value2[1] - max);
				for (i = 2; i <= n; i++) {
					if (value1[i] - abs(value2[i] - min) < elementMinim1) {
						elementMinim1 = value1[i] - abs(value2[i] - min);
					}
					if (value1[i] - abs(value2[i] - max) < elementMinim2) {
						elementMinim2 = value1[i] - abs(value2[i] - max);
					}
				}
				double mijloc = (min + max) / 2.0;
				if (elementMinim1 < elementMinim2) {
					min = mijloc;
					elementMinim = elementMinim2;

				} else {
					max = mijloc;
					elementMinim = elementMinim1;
				}
			}

			return String.format("%.1f", elementMinim);
		}


	}

	public static void main(String[] args) {
		new Task().solve();
	}
}
